class ReActAgent:
    def __init__(self, llm, tools):
        self.llm = llm
        self.tools = tools
        self.memory = []

    def think(self, query):
        """生成思考"""
        prompt = f"根据问题和记忆，生成下一步思考：\n"
        prompt += f"问题：{query}\n"
        prompt += f"记忆：{self.memory}\n"
        return self.llm.generate(prompt)

    def act(self, thought):
        """执行行动"""
        # 解析思考，选择合适的工具
        for tool in self.tools:
            if tool.name in thought:
                return tool.execute(thought)
        return None

    def run(self, query, max_steps=5):
        for step in range(max_steps):
            thought = self.think(query)
            action = self.act(thought)
            observation = action.result if action else "无结果"
            self.memory.append((thought, action, observation))
            if self.is_complete(observation):
                break
        return self.generate_answer()

class MemorySystem:
    def __init__(self, vector_db, embedding_model):
        self.short_term = []  # 短期记忆
        self.long_term = vector_db  # 长期记忆
        self.embedding = embedding_model

    def add_short_term(self, info):
        """添加短期记忆"""
        self.short_term.append(info)
        if len(self.short_term) > 20:
            self.short_term.pop(0)

    def add_long_term(self, docs):
        """添加长期记忆"""
        vectors = self.embedding.encode(docs)
        self.long_term.add(vectors, docs)

    def retrieve(self, query, k=3):
        """检索相关记忆"""
        query_vec = self.embedding.encode([query])[0]
        results = self.long_term.search(query_vec, k=k)
        return results

    def get_context(self, query):
        """获取完整上下文"""
        retrieved = self.retrieve(query)
        context = "\n".join([doc for _, doc in retrieved])
        context += "\n\n对话历史：" + "\n".join(self.short_term[-5:])
        return context

