class RAGSystem:
    def __init__(self, memory, llm):
        self.memory = memory
        self.llm = llm

    def answer(self, query):
        context = self.memory.get_context(query)
        prompt = f"基于以下上下文回答问题：\n{context}\n\n问题：{query}"
        return self.llm.generate(prompt)

import json
import time
from dataclasses import dataclass
from typing import Any, Optional

@dataclass
class MCPMessage:
    """MCP 消息结构"""
    from_agent: str
    to_agent: str
    action: str
    payload: dict
    message_id: str = None
    timestamp: float = None

    def __post_init__(self):
        if self.message_id is None:
            self.message_id = f"msg_{int(time.time() * 1000)}"
        if self.timestamp is None:
            self.timestamp = time.time()

    def to_json(self):
        """序列化为 JSON"""
        return json.dumps({
            'header': {
                'from': self.from_agent,
                'to': self.to_agent,
                'message_id': self.message_id,
                'timestamp': self.timestamp
            },
            'body': {
                'action': self.action,
                'payload': self.payload
            }
        }, indent=2)

    @classmethod
    def from_json(cls, json_str):
        """从 JSON 解析"""
        data = json.loads(json_str)
        return cls(
            from_agent=data['header']['from'],
            to_agent=data['header']['to'],
            action=data['body']['action'],
            payload=data['body']['payload'],
            message_id=data['header']['message_id'],
            timestamp=data['header']['timestamp']
        )

class MCPProtocol:
    """MCP 协议实现"""
    def initialize(self, provider_info):
        return MCPMessage(
            from_agent='client',
            to_agent='provider',
            action='initialize',
            payload=provider_info
        )

    def call(self, tool_name, arguments):
        return MCPMessage(
            from_agent='client',
            to_agent='provider',
            action='call',
            payload={'tool': tool_name, 'args': arguments}
        )

    def result(self, message_id, result, error=None):
        return MCPMessage(
            from_agent='provider',
            to_agent='client',
            action='result',
            payload={
                'message_id': message_id,
                'result': result,
                'error': error
            }
        )

