class BookingAgent:
    """预订智能体"""
    def __init__(self, travel_api):
        self.travel_api = travel_api

    def search_flights(self, from_city, to_city, date):
        return self.travel_api.search('flight', from_city, to_city, date)

    def search_hotels(self, city, dates, budget):
        return self.travel_api.search('hotel', city, dates, budget)

    def make_reservation(self, service_type, options):
        return self.travel_api.book(service_type, options)

    def make_reservations(self, itinerary):
        """批量预订"""
        bookings = {}
        # 预订交通
        bookings['transport'] = self.search_flights(
            itinerary['from'], itinerary['to'], itinerary['dates'][0]
        )
        # 预订酒店
        bookings['hotel'] = self.search_hotels(
            itinerary['destination'], itinerary['dates'], itinerary['budget']
        )
        return bookings

