class TravelAssistant:
    """旅行助手主协调器"""
    def __init__(self, llm, travel_api, knowledge_base):
        self.planner = PlannerAgent(llm)
        self.booking = BookingAgent(travel_api)
        self.advisor = AdvisorAgent(llm, knowledge_base)

    def plan_trip(self, request):
        """规划完整行程"""
        # 1. 创建行程
        itinerary = self.planner.create_itinerary(request)

        # 2. 并行执行预订和建议
        bookings = self.booking.make_reservations(itinerary)
        tips = self.advisor.give_advice(itinerary)

        # 3. 验证并最终化
        validated = self.planner.validate_itinerary(itinerary, bookings)

        # 4. 返回最终方案
        return self.planner.finalize_plan(validated, bookings, tips)
